import{_ as e,c as t,o as a,a as o}from"./app.b609ccdd.js";const f='{"title":"Create Preset","description":"","frontmatter":{},"headers":[{"level":2,"title":"Create Preset","slug":"create-preset"},{"level":3,"title":"Initialization","slug":"initialization"},{"level":3,"title":"Specify a project name","slug":"specify-a-project-name"},{"level":3,"title":"Specify a project template","slug":"specify-a-project-template"},{"level":3,"title":"Fetch latest configuration","slug":"fetch-latest-configuration"},{"level":3,"title":"Technology stack classification","slug":"technology-stack-classification"},{"level":3,"title":"Show and hide","slug":"show-and-hide"},{"level":3,"title":"Add technology stack","slug":"add-technology-stack"},{"level":2,"title":"Template","slug":"template"},{"level":3,"title":"About classification of sources","slug":"about-classification-of-sources"},{"level":3,"title":"Sort priority","slug":"sort-priority"},{"level":3,"title":"Rules for adding templates","slug":"rules-for-adding-templates"},{"level":3,"title":"Template URL description","slug":"template-url-description"},{"level":2,"title":"Configure","slug":"configure"},{"level":3,"title":"Manage local configuration","slug":"manage-local-configuration"},{"level":3,"title":"Prep work","slug":"prep-work"},{"level":3,"title":"Set configuration file","slug":"set-configuration-file"},{"level":3,"title":"Query configuration status","slug":"query-configuration-status"},{"level":3,"title":"Remove configuration settings","slug":"remove-configuration-settings"},{"level":3,"title":"Manage local tech stacks","slug":"manage-local-tech-stacks"},{"level":2,"title":"Proxy","slug":"proxy"},{"level":3,"title":"Turn On","slug":"turn-on"},{"level":3,"title":"Turn Off","slug":"turn-off"},{"level":2,"title":"Upgrade","slug":"upgrade"},{"level":3,"title":"Detect new version","slug":"detect-new-version"},{"level":3,"title":"Upgrade the CLI","slug":"upgrade-the-cli"},{"level":3,"title":"Change Log","slug":"change-log"}],"relativePath":"docs.md"}',n={},s=o(`<h2 id="create-preset" tabindex="-1">Create Preset <a class="header-anchor" href="#create-preset" aria-hidden="true">#</a></h2><p>Creating templates is the core feature of Preset CLI, which provides a variety of project templates for you to use.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The template list is under continuous improvement.</p></div><h3 id="initialization" tabindex="-1">Initialization <a class="header-anchor" href="#initialization" aria-hidden="true">#</a></h3><p>You can create a starter templates to your liking by <code>init</code> (alias <code>i</code>) command.</p><div class="language-bash"><pre><code>preset init
</code></pre></div><h3 id="specify-a-project-name" tabindex="-1">Specify a project name <a class="header-anchor" href="#specify-a-project-name" aria-hidden="true">#</a></h3><p>You can add a parameter as the project name, then you will skip the problem of entering the project name and choose the technology stack directly:</p><div class="language-bash"><pre><code>preset init hello-vue
</code></pre></div><h3 id="specify-a-project-template" tabindex="-1">Specify a project template <a class="header-anchor" href="#specify-a-project-template" aria-hidden="true">#</a></h3><p>You can directly specify a template to create a project with the <code>--template</code> option (requires <code>v0.12.0</code> above):</p><div class="language-bash"><pre><code><span class="token comment"># A project called \`hello-vue\` will be created using the \`vue3-ts-vite\` template</span>
preset init hello-vue --template vue3-ts-vite
</code></pre></div><h3 id="fetch-latest-configuration" tabindex="-1">Fetch latest configuration <a class="header-anchor" href="#fetch-latest-configuration" aria-hidden="true">#</a></h3><p>Preset CLI supports getting the latest technology stack list and starter template list without updating the version, because they are obtained through configuration files.</p><p>The configuration files are hosted in <a href="https://github.com/awesome-starter/website/tree/main/src/public/config" target="_blank" rel="noopener noreferrer">config</a> folder.</p><p>Therefore, after executing the <code>init</code> command, a network request will be initiated to fetch the configuration file.</p><h3 id="technology-stack-classification" tabindex="-1">Technology stack classification <a class="header-anchor" href="#technology-stack-classification" aria-hidden="true">#</a></h3><p>When creating a project, there will be a step to select the technology stack, You can easily find the template you need by classifying the technology stack.</p><p>The classification of the technology stack is based on core technologies, not related technologies. For example, a project using <code>Vite</code> + <code>TypeScript</code> + <code>Vue 3.0</code>, for the project, the core is <code>Vue 3.0</code>, so it will be classified under the <code>vue</code> category.</p><div class="language-bash"><pre><code>preset init

\u2714 Get the latest config successfully.

\u221A Project name: <span class="token punctuation">..</span>. my-preset-app
? Select a tech stack: \xBB - Use arrow-keys. Return to submit.
    vue
    react
    <span class="token function">node</span>
<span class="token operator">&gt;</span>   electron
    vite
    rollup
</code></pre></div><h3 id="show-and-hide" tabindex="-1">Show and hide <a class="header-anchor" href="#show-and-hide" aria-hidden="true">#</a></h3><p>Since <code>v0.10.0</code>, If a technology stack is added, but no corresponding template can be matched, it will be temporarily hidden and will not be displayed in the list of selectable technology stacks until it has a corresponding template associated with it.</p><h3 id="add-technology-stack" tabindex="-1">Add technology stack <a class="header-anchor" href="#add-technology-stack" aria-hidden="true">#</a></h3><p>At present, the technology stack needs to be maintained through the <a href="https://github.com/awesome-starter/website/blob/main/src/public/config/tech.json" target="_blank" rel="noopener noreferrer">tech.json</a> file on the official website.</p><p>If you need to add the missing stack, please add it to the file array in the following format.</p><div class="language-json"><pre><code><span class="token punctuation">{</span>
  <span class="token property">&quot;name&quot;</span><span class="token operator">:</span> <span class="token string">&quot;vue&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;color&quot;</span><span class="token operator">:</span> <span class="token string">&quot;#42b983&quot;</span>
<span class="token punctuation">}</span>
</code></pre></div><p>JSON field description:</p><table><thead><tr><th style="text-align:center;">Field</th><th style="text-align:center;">Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:center;">name</td><td style="text-align:center;">string</td><td style="text-align:left;">The name of the technology stack, please use the official recommended daily name</td></tr><tr><td style="text-align:center;">color</td><td style="text-align:center;">Color Hex</td><td style="text-align:left;">In order to have enough recognition and relevance, please take the color from the LOGO of the technology stack</td></tr></tbody></table><p>Please submit a PR, the technology stack will be added to the list after the merge.</p><h2 id="template" tabindex="-1">Template <a class="header-anchor" href="#template" aria-hidden="true">#</a></h2><p>Templates created through the Preset CLI are obtained through the Git repository.</p><h3 id="about-classification-of-sources" tabindex="-1">About classification of sources <a class="header-anchor" href="#about-classification-of-sources" aria-hidden="true">#</a></h3><p>Templates are classified into three sources: official maintenance, open source community, and local configuration.</p><table><thead><tr><th style="text-align:center;">Source</th><th style="text-align:left;">Description</th><th style="text-align:center;">Color</th><th style="text-align:center;">View</th></tr></thead><tbody><tr><td style="text-align:center;">Official Maintenance</td><td style="text-align:left;">Maintained by the official Awesome Starter team.</td><td style="text-align:center;">Yellow</td><td style="text-align:center;"><a href="https://github.com/awesome-starter/website/blob/main/src/public/config/official.json" target="_blank" rel="noopener noreferrer">official.json</a></td></tr><tr><td style="text-align:center;">Open Source Community</td><td style="text-align:left;">Excellent templates found from open source communities like GitHub.</td><td style="text-align:center;">White</td><td style="text-align:center;"><a href="https://github.com/awesome-starter/website/blob/main/src/public/config/community.json" target="_blank" rel="noopener noreferrer">community.json</a></td></tr><tr><td style="text-align:center;">Local Configuration</td><td style="text-align:left;">A config file that you store locally on your computer.</td><td style="text-align:center;">Cyan</td><td style="text-align:center;"><a href="#configure">Configure</a></td></tr></tbody></table><h3 id="sort-priority" tabindex="-1">Sort priority <a class="header-anchor" href="#sort-priority" aria-hidden="true">#</a></h3><p>Currently, it will be sorted according to the priority of &quot;Local Configuration&quot; &gt; &quot;Official Maintenance&quot; &gt; &quot;Open Source Community&quot;, and &quot;Local Configuration&quot; will be placed at the top of the list, which is convenient for your daily use.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Since <code>v0.10.0</code>, the order of community templates is no longer fixed, and the order will be randomly generated each time, in order to allow different templates to have enough opportunities to be exposed at the top.</p><p>If there are some community templates that you commonly use, please add them to the local configuration for easy search, so that they can be fixed at the top of the list.</p></div><h3 id="rules-for-adding-templates" tabindex="-1">Rules for adding templates <a class="header-anchor" href="#rules-for-adding-templates" aria-hidden="true">#</a></h3><p>The configuration file is in JSON format, so please follow the correct JSON syntax and add it to the array in the template file.</p><p>Each template currently specifies the following format:</p><div class="language-json"><pre><code><span class="token punctuation">{</span>
  <span class="token property">&quot;tech&quot;</span><span class="token operator">:</span> <span class="token string">&quot;vue&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;name&quot;</span><span class="token operator">:</span> <span class="token string">&quot;vue3-ts-vite&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;desc&quot;</span><span class="token operator">:</span> <span class="token string">&quot;A template for Vue 3.0 with TypeScript, base on Vite.&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;repo&quot;</span><span class="token operator">:</span> <span class="token string">&quot;https://github.com/awesome-starter/vue3-ts-vite-starter&quot;</span>
<span class="token punctuation">}</span>
</code></pre></div><p>JSON field description:</p><table><thead><tr><th style="text-align:center;">Field</th><th style="text-align:center;">Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:center;">tech</td><td style="text-align:center;">string</td><td style="text-align:left;">Technology stack, please check <a href="https://github.com/awesome-starter/website/blob/main/src/public/config/tech.json" target="_blank" rel="noopener noreferrer">here</a> for legal tech stack names.</td></tr><tr><td style="text-align:center;">name</td><td style="text-align:center;">string</td><td style="text-align:left;">Name of the template, please omit words like <code>template</code> or <code>starter</code>, just write the base name.</td></tr><tr><td style="text-align:center;">desc</td><td style="text-align:center;">string</td><td style="text-align:left;">Description of the template, one sentence to understand the characteristics of this template.</td></tr><tr><td style="text-align:center;">repo</td><td style="text-align:center;">string</td><td style="text-align:left;">Template repository URL, supports <code>https</code> and <code>git@</code> starting addresses, see the following <a href="#template-url-description">Template URL description</a></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Since the purpose of Awesome Starter is to provide excellent project templates, it only accepts repository collections of the Starter Template class. If you plan to make PR contributions to <a href="https://github.com/awesome-starter/website/blob/main/src/public/config/community.json" target="_blank" rel="noopener noreferrer">community.json</a>, please pay attention to this.</p><p>For the beauty of the list, currently the template name can display up to 20 characters, and the template description can display up to 80 characters. Exceeding the number of characters will end with <code>\u2026</code> ellipsis.</p></div><h3 id="template-url-description" tabindex="-1">Template URL description <a class="header-anchor" href="#template-url-description" aria-hidden="true">#</a></h3><p>Template URLs are supported in two formats: <a href="#https">HTTPS</a> and <a href="#ssh">SSH</a>.</p><h4 id="https" tabindex="-1">HTTPS <a class="header-anchor" href="#https" aria-hidden="true">#</a></h4><p>By default, HTTPS is used to configure for public repositories:</p><ul><li>If you use the <code>master</code> branch, just copy the access address of the repository in the browser directly</li><li>If it is a non-<code>master</code> branch such as <code>main</code> or <code>develop</code>, you need to concatenate <code>#</code> + branch name</li></ul><div class="language-bash"><pre><code><span class="token comment"># Use \`master\` as the master branch</span>
https://github.com/awesome-starter/vue3-ts-vite-starter

<span class="token comment"># Use \`main\` or other non-master branches</span>
<span class="token comment"># (the difference is the # sign with branch name at the end)</span>
https://github.com/awesome-starter/vue3-ts-vite-starter<span class="token comment">#main</span>
</code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>So, both the official template and the community template need to be configured this way, since they both have to be public repositories.</p></div><h4 id="ssh" tabindex="-1">SSH <a class="header-anchor" href="#ssh" aria-hidden="true">#</a></h4><p>If you configure your SSH Key correctly, you can download the template via SSH, which will pull the code in the form of <code>git clone</code>.</p><div class="language-bash"><pre><code><span class="token comment"># Copy the SSH download URL in the repository</span>
git@github.com: awesome-starter/create-preset.git
</code></pre></div><p>You can visit <a href="https://docs.github.com/en/authentication/connecting-to-github-with-ssh/working-with-ssh-key-passphrases" target="_blank" rel="noopener noreferrer">Working with SSH key passphrases</a> to learn how to configure SSH Key.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The provision of this method is mainly used to manage private repositories in the local configuration.</p></div><h2 id="configure" tabindex="-1">Configure <a class="header-anchor" href="#configure" aria-hidden="true">#</a></h2><p>Preset CLI provides a local configuration management function, which is convenient for you to manage commonly used private configurations.</p><h3 id="manage-local-configuration" tabindex="-1">Manage local configuration <a class="header-anchor" href="#manage-local-configuration" aria-hidden="true">#</a></h3><p>Local configuration management can be done through the <code>config</code> (alias <code>c</code>) command, which needs to be used in conjunction with subcommands.</p><h3 id="prep-work" tabindex="-1">Prep work <a class="header-anchor" href="#prep-work" aria-hidden="true">#</a></h3><p>Create a JSON file on your computer&#39;s hard drive and write the contents of the file in the following format:</p><p>For example: <code>F:\\config\\local-preset.json</code></p><div class="language-json"><pre><code><span class="token punctuation">[</span>
  <span class="token punctuation">{</span>
    <span class="token property">&quot;tech&quot;</span><span class="token operator">:</span> <span class="token string">&quot;vue&quot;</span><span class="token punctuation">,</span>
    <span class="token property">&quot;name&quot;</span><span class="token operator">:</span> <span class="token string">&quot;vue3-ts-vite&quot;</span><span class="token punctuation">,</span>
    <span class="token property">&quot;desc&quot;</span><span class="token operator">:</span> <span class="token string">&quot;A template for Vue 3.0 with TypeScript, base on Vite.&quot;</span><span class="token punctuation">,</span>
    <span class="token property">&quot;repo&quot;</span><span class="token operator">:</span> <span class="token string">&quot;https://github.com/awesome-starter/vue3-ts-vite-starter&quot;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">]</span>
</code></pre></div><p>In this way, a local configuration file is complete.</p><h3 id="set-configuration-file" tabindex="-1">Set configuration file <a class="header-anchor" href="#set-configuration-file" aria-hidden="true">#</a></h3><p>You can set the configuration file through the subcommand <code>set</code> of <code>config</code>. After setting, when Preset CLI reads the configuration, it will also read your local configuration.</p><div class="language-bash"><pre><code>preset config <span class="token builtin class-name">set</span> <span class="token operator">&lt;</span>filePath<span class="token operator">&gt;</span>
</code></pre></div><p>For example, using our previous example:</p><div class="language-"><pre><code>preset config set F:\\config\\local-preset.json
</code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If your file path has spaces, use <code>&quot;</code> double quotes around the path.</p></div><h3 id="query-configuration-status" tabindex="-1">Query configuration status <a class="header-anchor" href="#query-configuration-status" aria-hidden="true">#</a></h3><p>The currently set configuration file path can be queried through the <code>get</code> subcommand of <code>config</code>.</p><div class="language-bash"><pre><code>preset config get
</code></pre></div><p>This command is very useful if you forget where the configuration file is saved!</p><h3 id="remove-configuration-settings" tabindex="-1">Remove configuration settings <a class="header-anchor" href="#remove-configuration-settings" aria-hidden="true">#</a></h3><p>If you want to cancel the settings of the local configuration, you can cancel the settings with the <code>remove</code> subcommand of <code>config</code>.</p><div class="language-bash"><pre><code>preset config remove
</code></pre></div><h3 id="manage-local-tech-stacks" tabindex="-1">Manage local tech stacks <a class="header-anchor" href="#manage-local-tech-stacks" aria-hidden="true">#</a></h3><p>The <code>config</code> command also provides an option <code>--tech</code> (abbreviated <code>-t</code>), which is used to manage the local technology stack. When you add the <code>--tech</code> option, it will enter the technology stack management mode ( instead of template configuration).</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The operation commands of the local configuration and the local technology stack are the same, the only difference is that the technology stack needs to be added with the <code>--tech</code> option.</p></div><p>For example, if you want to set your local tech stack list, just add the <code>--tech</code> option:</p><div class="language-"><pre><code>preset config set F:\\config\\local-tech.json --tech
</code></pre></div><p>The template format of the local technology stack is:</p><div class="language-json"><pre><code><span class="token punctuation">[</span>
  <span class="token punctuation">{</span>
    <span class="token property">&quot;name&quot;</span><span class="token operator">:</span> <span class="token string">&quot;vue&quot;</span><span class="token punctuation">,</span>
    <span class="token property">&quot;color&quot;</span><span class="token operator">:</span> <span class="token string">&quot;#42b983&quot;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">]</span>
</code></pre></div><p>Please refer to the section <a href="#add-technology-stack">Add technology stack</a> for the description of JSON fields.</p><h2 id="proxy" tabindex="-1">Proxy <a class="header-anchor" href="#proxy" aria-hidden="true">#</a></h2><p>For the slow download problem in some areas, we provide the mirror proxy to speed up the download. You can use the <code>proxy</code> (alias <code>p</code>) command to turn on/off of the proxy . This command needs to be used in conjunction with subcommands.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>At present, the proxy service is only for GitHub&#39;s HTTPS download source, (Using <a href="https://doc.fastgit.org/" target="_blank" rel="noopener noreferrer">FastGit Mirror</a>), if you can&#39;t download after turn on the proxy, please turn off it.</p></div><h3 id="turn-on" tabindex="-1">Turn On <a class="header-anchor" href="#turn-on" aria-hidden="true">#</a></h3><p>The proxy service can be turned on with the <code>on</code> subcommand of <code>proxy</code>.</p><div class="language-bash"><pre><code>preset proxy on
</code></pre></div><p>Once enabled, FastGit&#39;s mirror service will be used to download starter templates.</p><h3 id="turn-off" tabindex="-1">Turn Off <a class="header-anchor" href="#turn-off" aria-hidden="true">#</a></h3><p>The proxy service can be turned off with the <code>off</code> subcommand of <code>proxy</code>.</p><div class="language-bash"><pre><code>preset proxy off
</code></pre></div><p>After the proxy is turned off, it will be downloaded directly from the GitHub URL, and will no longer be mirrored.</p><h2 id="upgrade" tabindex="-1">Upgrade <a class="header-anchor" href="#upgrade" aria-hidden="true">#</a></h2><p>Preset CLI provides the feature of new version detection, which is convenient for you to know whether there is a new version at any time.</p><h3 id="detect-new-version" tabindex="-1">Detect new version <a class="header-anchor" href="#detect-new-version" aria-hidden="true">#</a></h3><p>You can with <code>upgrade</code> (alias <code>u</code>) command to detect new version, and if a new version of the Preset CLI is released, you will be asked if you need to upgrade.</p><h3 id="upgrade-the-cli" tabindex="-1">Upgrade the CLI <a class="header-anchor" href="#upgrade-the-cli" aria-hidden="true">#</a></h3><p>When a new version is detected, the command line will ask you if you need to upgrade:</p><ul><li>Select &quot;Y&quot; will proceed to the process of installing the new version</li><li>Select &quot;N&quot; to exit the upgrade process</li></ul><div class="language-bash"><pre><code>preset upgrade

\u280F Detecting upgrade information\u2026
\u2714 Detected successfully.

  The current version: <span class="token number">0.6</span>.8
  The latest version: <span class="token number">0.6</span>.9
\u221A Found a new version, <span class="token keyword">do</span> you need to upgrade? <span class="token punctuation">..</span>. <span class="token function">yes</span>

? Please <span class="token keyword">select</span> your package manager <span class="token keyword">for</span> global installation \xBB
    <span class="token function">npm</span>
<span class="token operator">&gt;</span>   <span class="token function">yarn</span>
    <span class="token function">pnpm</span>
</code></pre></div><h3 id="change-log" tabindex="-1">Change Log <a class="header-anchor" href="#change-log" aria-hidden="true">#</a></h3><p>You can learn about the functional changes brought by each version upgrade at <a href="https://github.com/awesome-starter/create-preset/releases" target="_blank" rel="noopener noreferrer">Release Notes</a>.</p>`,107),i=[s];function r(c,l,p,d,h,u){return a(),t("div",null,i)}var m=e(n,[["render",r]]);export{f as __pageData,m as default};
